<script setup lang="ts">
import { BUSINESS_CAPABILITIES, BUSINESS_DOMAINS, type BusinessCapability, type BusinessDomain } from '~/config/businessCapabilities'
definePageMeta({ layout: 'default' })
const supabase = useSupabaseClient<any>(); const active = ref<BusinessDomain>('operations'); const data = ref<any>(); const loading = ref(true); const busy = ref(false); const error = ref(''); const message = ref(''); const selected = ref<BusinessCapability>()
const form = reactive({ objective: '', employee_name: '', employee_email: '', role_title: '', jurisdiction: '', start_date: '', purpose: '', context: '', brief: '', controls: { format: 'editable source', variants: 3, accessibility: true } })
const capabilities = computed(() => BUSINESS_CAPABILITIES.filter(item => item.domain === active.value)); const domain = computed(() => BUSINESS_DOMAINS.find(item => item.id === active.value))
const money = (value: any) => Number(value || 0).toLocaleString(undefined, { style: 'currency', currency: 'USD', maximumFractionDigits: 0 })
const relative = (value: string) => { const seconds = Math.max(0, (Date.now() - new Date(value).getTime()) / 1000); return seconds < 60 ? 'now' : seconds < 3600 ? `${Math.floor(seconds / 60)}m` : seconds < 86400 ? `${Math.floor(seconds / 3600)}h` : `${Math.floor(seconds / 86400)}d` }
const tone = (state: string) => ['completed','ready'].includes(state) ? 'bg-emerald-50 text-emerald-700' : ['approval_required','legal_review','evidence_required'].includes(state) ? 'bg-amber-50 text-amber-700' : ['blocked','failed'].includes(state) ? 'bg-red-50 text-red-700' : 'bg-gray-100 text-gray-600'
async function authedFetch<T>(url: string, options: any = {}) { const { data: { session } } = await supabase.auth.getSession(); return $fetch<T>(url, { ...options, headers: { ...(options.headers || {}), ...(session?.access_token ? { authorization: `Bearer ${session.access_token}` } : {}) } }) }
async function load() { loading.value = true; error.value = ''; try { data.value = await authedFetch('/api/business') } catch (e: any) { error.value = e?.data?.message || e?.message || 'Business OS could not load.' } finally { loading.value = false } }
function open(item: BusinessCapability) { selected.value = item; form.objective = item.outcome; message.value = ''; error.value = '' }
async function run() { if (!selected.value) return; busy.value = true; error.value = ''; try { const result: any = await authedFetch('/api/business/action', { method: 'POST', body: { action: selected.value.action, objective: form.objective, values: { ...form, controls: { ...form.controls } } } }); message.value = result.execution.approval_required ? 'Prepared with evidence and routed for independent approval.' : result.artifact?.status === 'connector_required' ? 'Job prepared. Connect a compatible provider to generate.' : 'Plan created and activation proof recorded.'; selected.value = undefined; await load() } catch (e: any) { error.value = e?.data?.message || e?.message || 'The action could not be prepared.' } finally { busy.value = false } }
onMounted(load)
</script>

<template><main class="min-h-full bg-[#fafbf9] text-[#171817]"><header class="border-b border-gray-200 bg-[radial-gradient(circle_at_83%_12%,#e8e7ff,transparent_27%),linear-gradient(145deg,#fff,#f2f4ef)]"><div class="mx-auto max-w-[1180px] px-6 pt-14"><div class="text-[10px] font-bold uppercase tracking-[.15em] text-indigo-700"><i class="mr-2 inline-block h-2 w-2 rounded-full bg-indigo-600 ring-4 ring-indigo-100"/>Business operating system</div><div class="mt-5 flex flex-col justify-between gap-10 lg:flex-row lg:items-end"><div><h1 class="text-5xl font-semibold leading-none tracking-[-.055em] md:text-7xl">Run the business.<br><em class="not-italic text-gray-500">See only what needs you.</em></h1><p class="mt-5 max-w-3xl text-sm leading-7 text-gray-600">People, money, creative production, legal evidence, and priorities share one governed action layer. Madeus prepares work, proves effects, and asks only for consequential decisions.</p></div><aside class="shrink-0 border-l border-gray-300 pl-5 lg:w-60"><span class="text-[9px] uppercase tracking-wider text-gray-400">Autonomy posture</span><b class="mt-2 block">Exception-driven</b><small class="mt-1 block text-[10px] leading-4 text-gray-500">Planning automatic · consequential actions approval-gated</small></aside></div><nav class="mt-12 grid md:grid-cols-4"><button v-for="item in BUSINESS_DOMAINS" :key="item.id" class="flex min-h-24 gap-3 border border-b-0 border-gray-300 p-4 text-left md:border-r-0 md:last:border-r" :class="active===item.id?'bg-gray-950 text-white':'bg-white/60'" @click="active=item.id"><i class="grid h-7 w-7 shrink-0 place-items-center rounded-lg bg-indigo-50 text-xs not-italic text-indigo-700">{{item.icon}}</i><span><b class="block text-xs">{{item.label}}</b><small class="mt-1 block text-[9px] leading-4" :class="active===item.id?'text-gray-400':'text-gray-500'">{{item.summary}}</small></span></button></nav></div></header>
<div class="mx-auto max-w-[1180px] space-y-16 px-6 py-9"><p v-if="error" class="rounded-xl border border-red-200 bg-red-50 p-3 text-xs text-red-700">{{error}}</p><p v-if="message" class="rounded-xl border border-emerald-200 bg-emerald-50 p-3 text-xs text-emerald-700">{{message}}</p><div v-if="loading" class="rounded-2xl border border-dashed bg-white p-14 text-center text-xs text-gray-500">Assembling the operating picture…</div><template v-else-if="data">
<section class="grid overflow-hidden rounded-2xl border bg-white sm:grid-cols-2 lg:grid-cols-4"><article v-for="metric in [{l:'Net recorded',v:money(data.summary.net),s:`${money(data.summary.income)} in · ${money(data.summary.expenses)} out`},{l:'Needs attention',v:data.summary.actions_waiting+data.summary.attention,s:'Approvals and financial exceptions'},{l:'People in motion',v:data.summary.people_in_flight,s:'Consent-first lifecycle cases'},{l:'Studio readiness',v:[data.studio.motion_ready,data.studio.image_ready,data.studio.spatial_ready].filter(Boolean).length+'/3',s:'Motion · image · spatial routes'}]" :key="metric.l" class="border-b p-5 last:border-0 sm:border-r lg:border-b-0"><span class="text-[9px] uppercase tracking-wider text-gray-400">{{metric.l}}</span><b class="mt-2 block text-3xl tracking-tight">{{metric.v}}</b><small class="mt-1 block text-[9px] text-gray-400">{{metric.s}}</small></article></section>
<section><header class="mb-5 flex flex-col justify-between gap-4 md:flex-row md:items-end"><div><span class="text-[10px] font-bold uppercase tracking-[.15em] text-indigo-700">{{domain?.label}} workspace</span><h2 class="mt-2 max-w-3xl text-2xl font-semibold tracking-tight">{{domain?.summary}}</h2></div><p class="max-w-sm text-[10px] leading-4 text-gray-500">Every launch creates a durable action record, guardrails, and activation proof.</p></header><div class="grid gap-3 md:grid-cols-2 lg:grid-cols-3"><article v-for="item in capabilities" :key="item.id" class="flex min-h-80 flex-col rounded-2xl border bg-white p-5"><div class="flex justify-between"><span class="rounded-full px-2 py-1 text-[8px] uppercase" :class="item.risk==='high'?'bg-red-50 text-red-700':item.risk==='medium'?'bg-amber-50 text-amber-700':'bg-emerald-50 text-emerald-700'">{{item.risk}} risk</span><i class="not-italic text-gray-400">↗</i></div><h3 class="mt-7 text-xl font-semibold tracking-tight">{{item.name}}</h3><p class="mt-2 text-[11px] leading-5 text-gray-600">{{item.summary}}</p><small class="mt-auto border-t pt-4 text-[10px]"><b class="mb-1 block text-[8px] uppercase tracking-wider text-gray-400">Output</b>{{item.outcome}}</small><button class="mt-4 rounded-lg bg-gray-950 px-4 py-2.5 text-[10px] font-semibold text-white" @click="open(item)">{{item.risk==='high'?'Prepare governed action':'Build plan'}}</button></article></div></section>
<section v-if="active==='creative'" class="grid gap-10 rounded-2xl bg-gray-950 p-8 text-white lg:grid-cols-2"><div><span class="text-[10px] font-bold uppercase tracking-[.15em] text-indigo-300">On-platform production fabric</span><h2 class="mt-2 text-3xl font-semibold">Vendor-neutral by design.</h2><p class="mt-3 text-[11px] leading-5 text-gray-400">Madeus selects a connected provider and preserves editable sources, provenance, licenses, review state, and derivatives in one job.</p></div><div><article v-for="route in [{label:'Motion',ready:data.studio.motion_ready,providers:'Runway · Adobe · fal'},{label:'Layered image',ready:data.studio.image_ready,providers:'Adobe · OpenAI · fal · Replicate'},{label:'3D & spatial',ready:data.studio.spatial_ready,providers:'Meshy · Adobe Substance'}]" :key="route.label" class="flex items-center gap-3 border-b border-gray-800 py-3"><i class="h-2 w-2 rounded-full" :class="route.ready?'bg-emerald-400':'bg-amber-400'"/><span class="flex-1"><b class="block text-xs">{{route.label}}</b><small class="text-[9px] text-gray-500">{{route.providers}}</small></span><NuxtLink v-if="!route.ready" to="/connectors" class="text-[9px] text-indigo-300">Connect</NuxtLink><em v-else class="text-[9px] not-italic text-emerald-300">Ready</em></article></div></section>
<section v-if="active==='workforce'" class="grid gap-5 rounded-2xl border border-emerald-200 bg-emerald-50 p-6 md:grid-cols-[40px_1fr_auto]"><i class="grid h-9 w-9 place-items-center rounded-lg bg-emerald-100 not-italic text-emerald-700">◎</i><div><span class="text-[10px] font-bold uppercase tracking-[.15em] text-emerald-700">Workforce intelligence contract</span><h3 class="mt-2 font-semibold">Improve the system of work—not a secret score about a person.</h3><p class="mt-2 max-w-2xl text-[10px] leading-4 text-emerald-900/70">Employee-controlled wellbeing inputs remain private. Leaders receive cohort capacity, workload design, recovery, staffing, and benefits recommendations only.</p></div><ul class="list-disc pl-4 text-[9px] leading-5 text-emerald-800"><li>No protected-trait inference</li><li>No private-message inspection</li><li>No individual health score</li><li>Minimum cohort {{data.privacy.minimum_cohort}}</li></ul></section>
<section><header class="mb-5 flex items-end justify-between"><div><span class="text-[10px] font-bold uppercase tracking-[.15em] text-indigo-700">Proof-carrying activity</span><h2 class="mt-2 text-2xl font-semibold">Recent operating actions</h2></div><button class="rounded-lg border bg-white px-3 py-2 text-[10px]" @click="load">↻ Refresh</button></header><div v-if="!data.runs.length" class="rounded-2xl border border-dashed bg-white p-12 text-center text-xs text-gray-500">No Business OS actions yet. Start with a plan above.</div><div v-else class="overflow-hidden rounded-2xl border bg-white"><article v-for="run in data.runs" :key="run.id" class="grid grid-cols-[1fr_auto_auto] items-center gap-3 border-b px-4 py-3 last:border-0"><div><b class="block text-[10px]">{{run.objective}}</b><small class="text-[8px] text-gray-400">{{run.domain}} · {{run.action.replaceAll('_',' ')}}</small></div><span class="rounded-full px-2 py-1 text-[8px]" :class="tone(run.state)">{{run.state.replaceAll('_',' ')}}</span><time class="text-[8px] text-gray-400">{{relative(run.created_at)}}</time></article></div></section>
</template></div>
<Teleport to="body"><div v-if="selected" class="fixed inset-0 z-[200] grid place-items-center overflow-y-auto bg-gray-950/60 p-4 backdrop-blur-sm" role="dialog" aria-modal="true" :aria-label="selected.name" @mousedown.self="!busy&&(selected=undefined)"><form class="max-h-[92vh] w-full max-w-2xl overflow-auto rounded-2xl bg-white shadow-2xl" @submit.prevent="run"><header class="flex justify-between border-b p-5"><div><span class="text-[9px] uppercase tracking-wider text-indigo-700">{{selected.domain}} · {{selected.risk}} risk</span><h2 class="mt-1 text-xl font-semibold">{{selected.name}}</h2><p class="mt-1 text-[10px] text-gray-500">{{selected.summary}}</p></div><button type="button" aria-label="Close" class="text-2xl text-gray-400" @click="selected=undefined">×</button></header><div class="grid gap-3 p-5 sm:grid-cols-2"><label class="sm:col-span-2 text-[9px] font-semibold text-gray-600">Outcome<textarea v-model="form.objective" rows="2" required class="mt-1 block w-full rounded-lg border p-2 text-xs"/></label><template v-if="['employee_onboarding','nda_draft'].includes(selected.action)"><label class="text-[9px] font-semibold">Name<input v-model="form.employee_name" required class="mt-1 block w-full rounded-lg border p-2 text-xs"/></label><label class="text-[9px] font-semibold">Email<input v-model="form.employee_email" type="email" required class="mt-1 block w-full rounded-lg border p-2 text-xs"/></label></template><label v-if="selected.action==='employee_onboarding'" class="text-[9px] font-semibold">Role title<input v-model="form.role_title" required class="mt-1 block w-full rounded-lg border p-2 text-xs"/></label><label v-if="selected.action==='employee_onboarding'" class="text-[9px] font-semibold">Start date<input v-model="form.start_date" type="date" class="mt-1 block w-full rounded-lg border p-2 text-xs"/></label><label v-if="selected.requires.includes('jurisdiction')" class="text-[9px] font-semibold">Jurisdiction<input v-model="form.jurisdiction" required class="mt-1 block w-full rounded-lg border p-2 text-xs"/></label><label v-if="selected.action==='nda_draft'" class="sm:col-span-2 text-[9px] font-semibold">Purpose<textarea v-model="form.purpose" rows="2" class="mt-1 block w-full rounded-lg border p-2 text-xs"/></label><label v-if="selected.action==='tax_strategy'" class="sm:col-span-2 text-[9px] font-semibold">Business and tax context<textarea v-model="form.context" rows="4" class="mt-1 block w-full rounded-lg border p-2 text-xs"/></label><label v-if="selected.domain==='creative'" class="sm:col-span-2 text-[9px] font-semibold">Creative brief<textarea v-model="form.brief" rows="5" required class="mt-1 block w-full rounded-lg border p-2 text-xs"/></label><aside class="sm:col-span-2 rounded-xl bg-gray-100 p-3"><b class="text-[10px]">Execution boundary</b><p class="mt-1 text-[9px] leading-4 text-gray-500">{{selected.risk==='high'?'Madeus prepares evidence and a review-ready artifact. It will not issue, file, sign, pay, or bind the organization without independent approval.':'Madeus creates a reversible plan or production job and records activation evidence.'}}</p></aside></div><footer class="flex justify-end gap-2 border-t p-4"><button type="button" class="rounded-lg border px-4 py-2 text-[10px]" @click="selected=undefined">Cancel</button><button :disabled="busy" class="rounded-lg bg-gray-950 px-4 py-2 text-[10px] text-white disabled:opacity-50">{{busy?'Preparing…':selected.risk==='high'?'Prepare for approval':'Create plan'}}</button></footer></form></div></Teleport></main></template>
